import{_ as e,c as a,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Copilot クォータ確認 | opencode-mystatus","description":"GitHub Copilot の Premium Requests 使用状況を確認する方法を学びます。サブスクリプション別のクォータと認証方式を解説します。","frontmatter":{"title":"Copilot クォータ確認 | opencode-mystatus","sidebarTitle":"クォータ確認","subtitle":"GitHub Copilotクォータクエリ：Premium Requestsとモデル詳細","description":"GitHub Copilot の Premium Requests 使用状況を確認する方法を学びます。サブスクリプション別のクォータと認証方式を解説します。","tags":["github-copilot","quota","premium-requests","pat-authentication"],"prerequisite":["start-quick-start"],"order":3},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/platforms/copilot-usage/index.md","filePath":"ja/vbgate/opencode-mystatus/platforms/copilot-usage/index.md"}'),l={name:"ja/vbgate/opencode-mystatus/platforms/copilot-usage/index.md"};function o(n,t,p,r,d,u){return s(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="github-copilotクォータクエリ-premium-requestsとモデル詳細" tabindex="-1">GitHub Copilotクォータクエリ：Premium Requestsとモデル詳細 <a class="header-anchor" href="#github-copilotクォータクエリ-premium-requestsとモデル詳細" aria-label="Permalink to &quot;GitHub Copilotクォータクエリ：Premium Requestsとモデル詳細&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><ul><li>GitHub CopilotのPremium Requests月次使用状況を素早く確認する</li><li>異なるサブスクリプションタイプ（Free/Pro/Pro+/Business/Enterprise）のクォータ差異を理解する</li><li>モデル使用詳細（GPT-4、Claudeなど）の使用回数を確認する</li><li>超過使用回数を識別し、追加費用を予測する</li><li>新OpenCode統合の権限問題を解決する（OAuth Tokenでクォータをクエリできない）</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">新OpenCode統合の権限問題</p><p>OpenCodeの最新OAuth統合は <code>/copilot_internal/*</code> APIへのアクセス権限を付与しないため、元のOAuth Token方式でクォータをクエリできなくなりました。</p><p>次のようなエラーが表示される場合があります：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot クォータクエリが一時的に利用できません。</span></span>
<span class="line"><span>OpenCodeの新しいOAuth統合はクォータAPIへのアクセスをサポートしていません。</span></span></code></pre></div><p>これは正常です。このチュートリアルで解決方法を教えます。</p></div><h2 id="核心コンセプト" tabindex="-1">核心コンセプト <a class="header-anchor" href="#核心コンセプト" aria-label="Permalink to &quot;核心コンセプト&quot;">​</a></h2><p>GitHub Copilotのクォータは以下の核心概念に分かれます：</p><h3 id="premium-requests-主要クォータ" tabindex="-1">Premium Requests（主要クォータ） <a class="header-anchor" href="#premium-requests-主要クォータ" aria-label="Permalink to &quot;Premium Requests（主要クォータ）&quot;">​</a></h3><p>Premium RequestsはCopilotの主要なクォータ指標で、以下を含みます：</p><ul><li>Chat対話（AIアシスタントとの対話）</li><li>Code Completion（コード補完）</li><li>Copilot Workspace機能（ワークスペースコラボレーション）</li></ul><div class="tip custom-block"><p class="custom-block-title">Premium Requestsとは？</p><p>簡単に理解すると：Copilotが「作業」を完了するたび（コード生成、質問回答、コード分析）が1回のPremium Requestとなります。これがCopilotの主要な計算単位です。</p></div><h3 id="サブスクリプションタイプとクォータ" tabindex="-1">サブスクリプションタイプとクォータ <a class="header-anchor" href="#サブスクリプションタイプとクォータ" aria-label="Permalink to &quot;サブスクリプションタイプとクォータ&quot;">​</a></h3><p>異なるサブスクリプションタイプには異なる月次クォータがあります：</p><table tabindex="0"><thead><tr><th>サブスクリプションタイプ</th><th>月次クォータ</th><th>適用対象</th></tr></thead><tbody><tr><td>Free</td><td>50回</td><td>個人開発者試用</td></tr><tr><td>Pro</td><td>300回</td><td>個人開発者正式版</td></tr><tr><td>Pro+</td><td>1,500回</td><td>ヘビーユーザー個人版</td></tr><tr><td>Business</td><td>300回</td><td>チームサブスクリプション（各アカウント300）</td></tr><tr><td>Enterprise</td><td>1,000回</td><td>エンタープライズサブスクリプション（各アカウント1000）</td></tr></tbody></table><h3 id="超過使用" tabindex="-1">超過使用 <a class="header-anchor" href="#超過使用" aria-label="Permalink to &quot;超過使用&quot;">​</a></h3><p>月次クォータを超えると、Copilotは引き続き使用できますが、追加費用が発生します。超過使用回数は出力で個別に表示されます。</p><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-クエリコマンドを実行" tabindex="-1">ステップ1：クエリコマンドを実行 <a class="header-anchor" href="#ステップ1-クエリコマンドを実行" aria-label="Permalink to &quot;ステップ1：クエリコマンドを実行&quot;">​</a></h3><p>OpenCodeでスラッシュコマンドを実行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><p>Copilotアカウントが設定されている場合（Fine-grained PATまたはOAuth Tokenを使用）、出力には以下のような内容が含まれます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## GitHub Copilot アカウントクォータ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        GitHub Copilot (pro)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Premium Requests [████████░░░░░░░░░░] 40% (180/300)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>モデル使用詳細:</span></span>
<span class="line"><span>  gpt-4: 120 requests</span></span>
<span class="line"><span>  claude-3-5-sonnet: 60 requests</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Period: 2026-01</span></span></code></pre></div><h3 id="ステップ2-出力結果を読み取る" tabindex="-1">ステップ2：出力結果を読み取る <a class="header-anchor" href="#ステップ2-出力結果を読み取る" aria-label="Permalink to &quot;ステップ2：出力結果を読み取る&quot;">​</a></h3><p>出力には以下の主要情報が含まれます：</p><h4 id="_1-アカウント情報" tabindex="-1">1. アカウント情報 <a class="header-anchor" href="#_1-アカウント情報" aria-label="Permalink to &quot;1. アカウント情報&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        GitHub Copilot (pro)</span></span></code></pre></div><p>Copilotサブスクリプションタイプ（pro/free/businessなど）を表示します。</p><h4 id="_2-premium-requestsクォータ" tabindex="-1">2. Premium Requestsクォータ <a class="header-anchor" href="#_2-premium-requestsクォータ" aria-label="Permalink to &quot;2. Premium Requestsクォータ&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Premium Requests [████████░░░░░░░░░░] 40% (180/300)</span></span></code></pre></div><ul><li><strong>プログレスバー</strong>：残り比率を直感的に表示</li><li><strong>パーセンテージ</strong>：残り40%</li><li><strong>使用済み/総量</strong>：使用済み180回、総量300回</li></ul><div class="tip custom-block"><p class="custom-block-title">プログレスバーの説明</p><p>緑色/黄色の塗りつぶしは使用済みを表し、空ブロックは残りを表します。塗りつぶしが多いほど使用量が多いことを表します。</p></div><h4 id="_3-モデル使用詳細-public-apiのみ" tabindex="-1">3. モデル使用詳細（Public APIのみ） <a class="header-anchor" href="#_3-モデル使用詳細-public-apiのみ" aria-label="Permalink to &quot;3. モデル使用詳細（Public APIのみ）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>モデル使用詳細:</span></span>
<span class="line"><span>  gpt-4: 120 requests</span></span>
<span class="line"><span>  claude-3-5-sonnet: 60 requests</span></span></code></pre></div><p>各モデルの使用回数を表示します。使用量で降順に並べ替え（最大5個まで表示）。</p><div class="info custom-block"><p class="custom-block-title">なぜ私の出力にモデル詳細がないのか？</p><p>モデル詳細はPublic API（Fine-grained PAT）方式でのみ表示されます。OAuth Token（Internal API）を使用している場合、モデル詳細は表示されません。</p></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下のステップを完了したら、以下ができるようになります：</p><ul><li>[ ] <code>/mystatus</code> 出力でGitHub Copilotクォータ情報を確認できる</li><li>[ ] Premium Requestsのプログレスバーとパーセンテージを理解できる</li><li>[ ] 自分のサブスクリプションタイプと月次クォータを把握している</li><li>[ ] モデル使用詳細を確認する方法を知っている（Fine-grained PATを使用する場合）</li><li>[ ] 超過使用の意味を理解している</li></ul><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>このチュートリアルでは、opencode-mystatusを使用してGitHub Copilotのクォータをクエリする方法を学びました：</p><p><strong>重要ポイント</strong>：</p><ol><li><strong>Premium Requests</strong>はCopilotの主要なクォータ指標で、Chat、Completion、Workspaceなどの機能を含みます</li><li><strong>サブスクリプションタイプ</strong>は月次クォータを決定します：Free 50回、Pro 300回、Pro+ 1,500回、Business 300回、Enterprise 1,000回</li><li><strong>超過使用</strong>は追加費用を発生させ、出力で個別に表示されます</li><li><strong>Fine-grained PAT</strong>は推奨される認証方式で、OpenCode OAuth統合の変更による影響を受けません</li><li><strong>OAuth Token</strong>方式は権限制限で失敗する可能性があり、PATを代替案として使用する必要があります</li></ol><p><strong>出力の解釈</strong>：</p><ul><li>プログレスバー：残り比率を直感的に表示</li><li>パーセンテージ：具体的な残り量</li><li>使用済み/総量：詳細な使用状況</li><li>モデル詳細（オプション）：各モデルの使用回数</li><li>リセット時間（オプション）：次回リセットまでのカウントダウン</li></ul><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../advanced/copilot-auth/">Copilot認証設定</a></strong> を学びます。</p><p>学べること：</p><ul><li>OAuth TokenとFine-grained PATの詳細な比較</li><li>Fine-grained PATを生成する方法（完全なステップ）</li><li>権限問題を解決する多様な方案</li><li>異なるシナリオでのベストプラクティス</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Copilotクォータクエリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>481-524</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Public Billing APIクエリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>157-177</td></tr><tr><td>Internal APIクエリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>242-304</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>COPILOT_PLAN_LIMITS</code>：各サブスクリプションタイプの月次クォータ（第397-403行） <ul><li><code>free: 50</code></li><li><code>pro: 300</code></li><li><code>pro+: 1500</code></li><li><code>business: 300</code></li><li><code>enterprise: 1000</code></li></ul></li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>queryCopilotUsage()</code>：メインクエリ関数、2つの認証戦略をサポート（第481-524行）</li><li><code>fetchPublicBillingUsage()</code>：Fine-grained PATを使用してPublic Billing APIをクエリ（第157-177行）</li><li><code>fetchCopilotUsage()</code>：OAuth Tokenを使用してInternal APIをクエリ（第242-304行）</li></ul></details>`,50)])])}const b=e(l,[["render",o]]);export{h as __pageData,b as default};
